import React, { useState } from 'react';
import ProductForm from '../components/ProductForm';
import ProductList from '../components/ProductList';
import StockMovementForm from '../components/StockMovementForm';
import axios from 'axios';

const Products = () => {
    const [products, setProducts] = useState([]);
    const [selectedProduct, setSelectedProduct] = useState(null); // Adicionando selectedProduct

    // Função para buscar produtos
    const fetchProducts = async () => {
        try {
            const response = await axios.get('http://127.0.0.1:8000/api/produtos/');
            console.log(response.data); // Exibir produtos no console para depuração
            setProducts(response.data);
        } catch (error) {
            console.error("Erro ao buscar produtos:", error);
        }
    };

    return (
        <div>
            <h2>Lista de Produtos</h2>
            <ProductForm 
                refreshProducts={fetchProducts} 
                selectedProduct={selectedProduct} 
                setSelectedProduct={setSelectedProduct} 
            />
            <ProductList 
                products={products} 
                onEdit={setSelectedProduct} 
            />
        </div>
    );
};

export default Products;
